INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('beast','system','UGV Beast',NULL,NULL,'BEAST-01','needs-attention','assembled','owner',true,'Waveshare UGV Beast ACCE ROS2 kit with the stock pan-tilt 5MP camera, OAK-D Lite depth camera, and D500 LiDAR. First unit of the fleet. Mid Orin cutover (2026-07-22): Raspberry Pi 5 removed; host mount empty while the owned Jetson Orin Nano Super is being fitted. Slow tracked base that stops on a dime — remote and on-device control are both viable once the host is back.',NULL,NULL,NULL,'2026',NULL,1,25,5,'5V',3200,NULL,NULL,'[{"label":"Chassis","value":"Tracked, all-terrain · slow, hard-stopping"},{"label":"Onboard host","value":"EMPTY — Orin Nano cutover in progress"},{"label":"Motor control","value":"ESP32 (PID)"},{"label":"Pan-tilt camera","value":"5MP · 160° · USB"},{"label":"Depth camera","value":"OAK-D Lite · USB"},{"label":"LiDAR","value":"D500 / STL-19P · 360° · 230400 baud"},{"label":"Pack","value":"3S Li-ion (~11.1V)"},{"label":"Control","value":"Offline until Orin host is fitted"}]'::jsonb,'[{"label":"Waveshare UGV Beast","url":"https://www.waveshare.com/ugv-beast.htm"},{"label":"Waveshare UGV hardware tutorial","url":"https://www.youtube.com/watch?v=8wqPs7rNkJ4"}]'::jsonb,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('oak-d-lite','module','Luxonis OAK-D Lite',NULL,NULL,'BEAST-RGBD','operational','assembled','owner',false,'OAK-D Lite depth and AI camera installed as part of the BEAST-01 ACCE ROS2 kit.',NULL,NULL,NULL,'included',NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"Role","value":"Stereo depth · RGB · onboard vision"},{"label":"Interface","value":"USB"},{"label":"ROS","value":"depthai_ros_driver"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('d500-lidar','module','Waveshare D500 LiDAR',NULL,NULL,'BEAST-LIDAR','operational','assembled','owner',false,'D500 360° DTOF LiDAR installed as part of the BEAST-01 ACCE ROS2 kit; the sensor core is STL-19P/LDS19.',NULL,NULL,NULL,'included',NULL,1,1.45,5,'5V',NULL,NULL,NULL,'[{"label":"Sensor","value":"STL-19P / LDS19"},{"label":"Range","value":"0.03–12 m"},{"label":"Scan","value":"360° · 10 Hz · 5000 samples/s"},{"label":"Interface","value":"UART · 230400 baud · USB bridge to host"},{"label":"ROS model","value":"LDLIDAR_MODEL=ld19"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('stock-ups','module','Stock 3x18650 UPS',NULL,NULL,'BEAST-PWR','operational','assembled','owner',false,'Stock undercarriage UPS module installed in BEAST-01, with room for 3x 18650 cells and external 3S pack experiments.',NULL,NULL,NULL,'included',NULL,1,NULL,11.1,'battery',NULL,NULL,NULL,'[{"label":"Cells","value":"3x 18650"},{"label":"Chassis slot","value":"Undercarriage Bay"},{"label":"Expansion","value":"External 3S packs via XH2.54 input"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('driver-board','module','General Driver for Robots',NULL,NULL,'BEAST-CTL','operational','assembled','owner',false,'Waveshare ESP32-WROOM-32 driver board at the heart of BEAST-01: motor H-bridge, ST3215 servo bus, 5V host rail for the Pi, IMU, and battery telemetry on one 65×65mm PCB.',NULL,NULL,NULL,'included',NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"MCU","value":"ESP32-WROOM-32"},{"label":"Power in","value":"XH2.54 · DC 7–13V"},{"label":"Motor driver","value":"TB6612FNG dual H-bridge"},{"label":"Servo bus","value":"ST3215 TTL @ 1 Mbps (5A limit)"},{"label":"Host rail","value":"5V buck (MP8759, ~5A) via 40-pin"},{"label":"Telemetry","value":"INA219 V/I sense · IMU · OLED I²C"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('rover-slot-2','module','Open Rover Slot',NULL,NULL,NULL,'wishlist','wishlist','inferred',false,'Reserved bay for the next ground unit or aerial drone as the fleet grows.',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"Status","value":"Empty — future acquisition"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('workstation','module','Threadripper / RTX 5090',NULL,NULL,'CORE-PRIME','operational','deployed','owner',true,'Blackwell-class desktop. Fleet brain for training and heavy perception/VLA inference. On the slow hard-stopping Beast, remote closed-loop over WiFi 6 is first-class alongside on-device Orin — the network tail is a design input, not a teleop veto.',NULL,NULL,NULL,'owned',NULL,1,600,NULL,'mains',NULL,NULL,NULL,'[{"label":"GPU","value":"RTX 5090 · 32GB GDDR7"},{"label":"Arch","value":"Blackwell"},{"label":"CPU","value":"Threadripper"},{"label":"Role","value":"Train + offboard inference"},{"label":"Link","value":"WiFi 6 LAN to fleet"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('pi5','module','Raspberry Pi 5',NULL,NULL,'EDGE-PI','retired','inventory','owner',false,'Former Beast upper computer — removed 2026-07-22 for the Orin Nano cutover. Kept in inventory as a spare SBC. No CUDA; when it was onboard it handled teleop, streaming, I/O, and the stale-command watchdog on the constrained 5V/5A rail.',NULL,NULL,NULL,'owned',NULL,1,25,5,'5V',NULL,NULL,NULL,'[{"label":"SoC","value":"BCM2712 · quad A76"},{"label":"GPU","value":"VideoCore (no CUDA)"},{"label":"Rail","value":"5V / 5A — protect it"},{"label":"Role","value":"Spare · former Beast host"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('orin-nano','module','Jetson Orin Nano Super',NULL,NULL,'BEAST-JETSON','needs-attention','assembled','owner',false,'Owned NVIDIA Jetson Orin Nano 8GB developer kit — JetPack 6.2.2 / R36.5 on NVMe, ROS 2 Humble and the Jetson-adapted Waveshare workspace built. Software-ready Beast host; physical install into the empty host mount is the active cutover blocker (2026-07-22).',NULL,NULL,NULL,'owned',NULL,1,25,NULL,'battery',NULL,249,NULL,'[{"label":"AI perf","value":"up to 67 TOPS (Super); ~1.7× prior"},{"label":"Arch","value":"Ampere GPU + 6-core Arm"},{"label":"Power","value":"7–25 W"},{"label":"Memory","value":"8 GB"},{"label":"Cameras","value":"2× MIPI CSI (4-lane)"},{"label":"Carrier","value":"Accepts Orin Nano + Orin NX"},{"label":"Stack","value":"CUDA · TensorRT · Isaac ROS"},{"label":"Lifecycle","value":"through 2032"},{"label":"Cutover","value":"Pi out · Orin fitting"}]'::jsonb,'[{"label":"NVIDIA Jetson Orin","url":"https://www.nvidia.com/en-us/autonomous-machines/embedded-systems/jetson-orin/"}]'::jsonb,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('jetson-thor','module','Jetson Thor (T4000)',NULL,NULL,NULL,'researching','wishlist','inferred',false,'Blackwell in an embedded module — but the wrong tier for a hobby rover. Built for humanoids and industrial AMRs. Logged for the research horizon, not the buy list.',NULL,NULL,NULL,NULL,'Q2 2026 · wrong tier',1,75,NULL,'battery',NULL,1999,NULL,'[{"label":"AI perf","value":"1,200 FP4 TFLOPS"},{"label":"Arch","value":"Blackwell"},{"label":"Power","value":"40–75 W"},{"label":"Memory","value":"64 GB"},{"label":"Price","value":"~$1,999 @ 1k vol"},{"label":"Avail","value":"~Q2 2026"}]'::jsonb,NULL,NULL,NULL);
