INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('power-rail','Power lights off the battery rail, not the Pi','RC crawler lights are rated 2S–3S, so they run straight off the ~11.1V pack through the driver board — drawing nothing from the constrained 5V/5A Pi rail. The elegant option is also the power-friendly one.','high',NULL,'2026-05-31');
