INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('video-device-path','Camera device paths can move after reboot','BEAST-01 video failed when the USB camera re-enumerated and Waveshare code kept opening hardcoded camera index 0. Use the stable /dev/v4l/by-id video-index0 path, or scan /dev/video* for the first readable capture device, then restart only the Flask app.','high',NULL,'2026-06-30');
