INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('calibration-burden','Separate camera + LiDAR = real calibration burden','You produce a 6-DOF rigid transform plus time sync. Sleeper problems: time sync (independent clocks smear points in motion) and drift (vibration + thermal cycling walk the extrinsic off true — worse on a tracked base). Standalone LiDAR also adds power draw.','high','koide3/direct_visual_lidar_calibration','2026-05-31');
