INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('blackwell-gap','No Blackwell Nano exists — yet','Blackwell in Jetson is top-end only (Thor T4000/T5000). The Nano/NX tiers are still Ampere. The genuinely Blackwell option you already own is the 5090 — which is exactly why offload-over-WiFi is worth taking seriously.','high',NULL,'2026-05-31');
