INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('ag2-repealed','Autonomy ban repealed — Hangar may self-drive units','2026-07-22: North Star AG2 (“not an autonomous system / human always in the loop”) is removed. New G7: Hangar hosts a live command portal including teleop and autonomous/learned policies. Onboard fail-safes remain mandatory engineering, not a product veto on closed-loop control.','high','docs/NORTH_STAR.md','2026-07-22');
